insert into offmarket.business_signals (business_id, layer, signal_key, direction, weight, evidence, source, source_url, observed_at) values
('079e27cc-fc0a-5e1c-b36c-966fd1f0c20d', 4, 'low_pe_attention_vertical', 'positive', NULL, 'TX land surveying = LOW-PE-ATTENTION vertical. Only Bowman Consulting (NASDAQ:BWMN) + Westwood Professional Services (Endeavour Capital) are PE-backed rollup platforms active in TX surveying. Large-AEC strategics (Stantec/WSP/AECOM/Kimley-Horn/Cobb Fendley/LJA) only bolt-on $5M+ rev firms. Sub-$5M independent universe (Lubbock, Lubbock County) structurally under-targeted = opportunity zone. ETA/search-fund appetite emerging fast 2024-2026 per Stanford Search Fund Study (top-15 ETA vertical).', 'verticals.md skill config + Stanford Search Fund Study + Bowman 10-K filings', 'https://pels.texas.gov/roster/ls_rosters.html', '2026-05-16'),
('079e27cc-fc0a-5e1c-b36c-966fd1f0c20d', 2, 'comptroller_status_verified', 'disqualifying', NULL, 'TX Comptroller Taxable Entity status: active (SOS file #?, formed ?, registered agent: ?).', 'tx_comptroller_taxable_entity_search', 'https://comptroller.texas.gov/taxes/franchise/account-status/search', '2026-05-16'),
('079e27cc-fc0a-5e1c-b36c-966fd1f0c20d', 3, 'successor_check_live_fetch', 'negative', NULL, 'Live team page at https://r2meng.com/r2m-team/ (fetched 2026-05-16). r2meng.com (search summary): multi-disciplined firm (civil + environmental + safety); 100+yr combined experience; Jeryl ''Jere'' D. Hart Jr. is VP Engineering + Surveying, mentors staff, lead surveyor for PS&E projects, 47+yr experience. The ''Jr.'' on the firm is the active operator. Lubbock TX, $unknown rev but multi-disciplined firm.', 'live_website_fetch', 'https://r2meng.com/r2m-team/', '2026-05-16'),
('118e9976-7606-5e6d-9829-c73de26a1c7f', 1, 'owner_age_proxy_rpls_tenure', 'positive', NULL, 'Senior RPLS David R. Collins (TBPELS license #1954) granted 1978-02-22 → 48yr tenure. TX RPLS requires 4yr college + 4yr supervised survey-in-training + state exam (typically earned at age 28-35); est. owner age ~78.', 'tbpels_rpls_roster', 'https://tbpedownloads.s3-us-west-2.amazonaws.com/rpls_roster.csv', '2026-05-16'),
('118e9976-7606-5e6d-9829-c73de26a1c7f', 2, 'firm_tenure_long', 'positive', NULL, 'Senior RPLS David R. Collins tenure 48yr per TBPELS RPLS roster. Firm registered as TBPELS Surveying Firm #10023000 since 2007-11-01. Passes >5yr settled-business hard gate.', 'tbpels_surveying_firms_roster', 'https://tbpedownloads.s3-us-west-2.amazonaws.com/sur-firm_roster.csv', '2026-05-16'),
